// Model-Based Reflex Agent
FUNCTION ModelBasedReflexAgent(percept) RETURNS action
 LOCAL STATIC: state, worldModel, rules

 // Update state based on current percept and previous action
 state <- UPDATE-STATE(state, action, percept, worldModel)

 // Find matching rule
 rule <- RULE-MATCH(state, rules)
 action <- rule.ACTION
 RETURN action

// Update State Function
FUNCTION UPDATE-STATE(state, action, percept, model)
 // Update internal state representation
 state.location <- percept.currentLocation
 state.dirty <- percept.dirtyStatus
 state.time <- state.time + 1

 // If we moved, update position in model
 IF action = MoveRight THEN state.position.x <- state.position.x + 1
 IF action = MoveLeft THEN state.position.x <- state.position.x - 1

 RETURN state

// Goal-Based Agent for Navigation
FUNCTION GoalBasedNavigator(percept) RETURNS action
 LOCAL STATIC: state, goal, problem, search

 // Update state from percept
 state <- UPDATE-STATE(state, percept)

 // Check if goal reached
 IF GOAL-TEST(state, goal) THEN RETURN NoOp

 // Find goal-directed action
 problem <- FORMULATE-PROBLEM(state, goal)
 action <- SEARCH(problem, search)
 RETURN action

// Problem Formulation
FUNCTION FORMULATE-PROBLEM(state, goal)
 RETURN Problem(
 initialState: state.currentPosition,
 actions: [MoveNorth, MoveSouth, MoveEast, MoveWest],
 goalTest: position == goal.destination,
 stepCost: 1
 )

// Simple Search
FUNCTION SEARCH(problem, method) RETURNS action
 path <- BFS(problem) // Breadth-first search
 RETURN First(path.actions)

// Learning Agent
FUNCTION LearningAgent(percept) RETURNS action
 LOCAL STATIC: performanceElement, learningElement, critic, problemGenerator

 // Performance element generates action
 action <- performanceElement.Execute(percept)

 // Critic evaluates performance
 feedback <- critic.Evaluate(percept, action)

 // Learning element improves performance element
 learningElement.LEARN(feedback)

 // Problem generator suggests exploratory actions
 IF problemGenerator.ShouldExplore() THEN
 action <- problemGenerator.Suggest()

 RETURN action

// Example Critic (for game-playing)
FUNCTION Evaluate(percept, action) RETURNS feedback
 oldScore <- percept.previousScore
 newScore <- percept.currentScore
 improvement <- newScore - oldScore
 RETURN PerformanceFeedback(
 improvement: improvement,
 action: action,
 percept: percept
 )
